-- Production PostgreSQL schema. Apply with the migration runner of your host.
CREATE TYPE user_role AS ENUM ('CUSTOMER','EDITOR','ADMIN');
CREATE TYPE publication_status AS ENUM ('DRAFT','SCHEDULED','PUBLISHED','ARCHIVED');
CREATE TYPE order_status AS ENUM ('PENDING','PAID','FAILED','CANCELLED','REFUNDED');
CREATE TYPE asset_kind AS ENUM ('MASTER','SAMPLE','COVER','GALLERY');
CREATE TABLE users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text UNIQUE NOT NULL, password_hash text, role user_role NOT NULL DEFAULT 'CUSTOMER', email_verified_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE customer_profiles (user_id uuid PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE, display_name text, phone text, newsletter_opt_in boolean NOT NULL DEFAULT false, deletion_requested_at timestamptz);
CREATE TABLE addresses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, label text, line1 text NOT NULL, line2 text, city text NOT NULL, region text, postal_code text, country_code char(2) NOT NULL, created_at timestamptz DEFAULT now());
CREATE TABLE languages (id serial PRIMARY KEY, code varchar(10) UNIQUE NOT NULL, name text NOT NULL, native_name text NOT NULL, direction varchar(3) NOT NULL CHECK(direction IN ('ltr','rtl')));
CREATE TABLE publishers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text UNIQUE NOT NULL);
CREATE TABLE authors (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text UNIQUE NOT NULL, bio text, language_id int REFERENCES languages(id), image_key text);
CREATE TABLE narrators (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text UNIQUE NOT NULL, bio text);
CREATE TABLE categories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), parent_id uuid REFERENCES categories(id), name text NOT NULL, slug text UNIQUE NOT NULL);
CREATE TABLE books (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slug text UNIQUE NOT NULL, original_title text NOT NULL, translated_title text, description text NOT NULL, short_description text, language_id int NOT NULL REFERENCES languages(id), author_id uuid NOT NULL REFERENCES authors(id), narrator_id uuid REFERENCES narrators(id), publisher_id uuid REFERENCES publishers(id), status publication_status NOT NULL DEFAULT 'DRAFT', isbn text, edition text, publication_date date, keywords text[], featured boolean DEFAULT false, bestseller boolean DEFAULT false, new_release boolean DEFAULT false, seo_title text, meta_description text, published_at timestamptz, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE INDEX books_search_idx ON books USING gin (to_tsvector('simple', coalesce(original_title,'') || ' ' || coalesce(translated_title,'') || ' ' || coalesce(description,'')));
CREATE TABLE book_translations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), book_id uuid NOT NULL REFERENCES books(id) ON DELETE CASCADE, locale varchar(10) NOT NULL, title text NOT NULL, description text, UNIQUE(book_id,locale));
CREATE TABLE book_categories (book_id uuid REFERENCES books(id) ON DELETE CASCADE, category_id uuid REFERENCES categories(id) ON DELETE CASCADE, PRIMARY KEY(book_id,category_id));
CREATE TABLE book_formats (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), book_id uuid NOT NULL REFERENCES books(id) ON DELETE CASCADE, kind varchar(20) NOT NULL, sku text UNIQUE NOT NULL, page_count int, duration_seconds int, file_size_bytes bigint, download_limit int NOT NULL DEFAULT 5, is_downloadable boolean DEFAULT true);
CREATE TABLE book_assets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), format_id uuid REFERENCES book_formats(id) ON DELETE CASCADE, kind asset_kind NOT NULL, storage_key text NOT NULL, mime_type text NOT NULL, bytes bigint NOT NULL, is_public boolean NOT NULL DEFAULT false, CHECK(kind <> 'MASTER' OR is_public = false));
CREATE TABLE book_images (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), book_id uuid REFERENCES books(id) ON DELETE CASCADE, storage_key text NOT NULL, alt_text text NOT NULL, sort_order int DEFAULT 0);
CREATE TABLE prices (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), format_id uuid REFERENCES book_formats(id) ON DELETE CASCADE, currency char(3) NOT NULL, amount_minor int NOT NULL CHECK(amount_minor >= 0), sale_amount_minor int CHECK(sale_amount_minor >= 0), starts_at timestamptz, ends_at timestamptz, UNIQUE(format_id,currency));
CREATE TABLE inventory (format_id uuid PRIMARY KEY REFERENCES book_formats(id) ON DELETE CASCADE, quantity int NOT NULL DEFAULT 0, low_stock_threshold int DEFAULT 5);
CREATE TABLE carts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES users(id), anonymous_token_hash text, expires_at timestamptz, created_at timestamptz DEFAULT now());
CREATE TABLE cart_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), cart_id uuid REFERENCES carts(id) ON DELETE CASCADE, format_id uuid REFERENCES book_formats(id), quantity int NOT NULL DEFAULT 1, UNIQUE(cart_id,format_id));
CREATE TABLE wishlists (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid UNIQUE REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE wishlist_items (wishlist_id uuid REFERENCES wishlists(id) ON DELETE CASCADE, book_id uuid REFERENCES books(id) ON DELETE CASCADE, created_at timestamptz DEFAULT now(), PRIMARY KEY(wishlist_id,book_id));
CREATE TABLE orders (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), order_number text UNIQUE NOT NULL, user_id uuid REFERENCES users(id), email text NOT NULL, status order_status DEFAULT 'PENDING', currency char(3) NOT NULL, subtotal_minor int NOT NULL, tax_minor int DEFAULT 0, discount_minor int DEFAULT 0, total_minor int NOT NULL, provider_session_id text UNIQUE, idempotency_key text UNIQUE NOT NULL, created_at timestamptz DEFAULT now(), paid_at timestamptz);
CREATE TABLE order_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), order_id uuid REFERENCES orders(id) ON DELETE CASCADE, format_id uuid REFERENCES book_formats(id), title_snapshot text NOT NULL, price_minor int NOT NULL, quantity int NOT NULL DEFAULT 1);
CREATE TABLE payments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), order_id uuid REFERENCES orders(id), provider text NOT NULL, provider_payment_id text UNIQUE, status text NOT NULL, amount_minor int NOT NULL, event_id text UNIQUE, payload_hash text, created_at timestamptz DEFAULT now());
CREATE TABLE coupons (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text UNIQUE NOT NULL, discount_type text NOT NULL, amount int NOT NULL, active boolean DEFAULT true, max_uses int, expires_at timestamptz);
CREATE TABLE coupon_usage (coupon_id uuid REFERENCES coupons(id), user_id uuid REFERENCES users(id), order_id uuid UNIQUE REFERENCES orders(id), used_at timestamptz DEFAULT now(), PRIMARY KEY(coupon_id,order_id));
CREATE TABLE reviews (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES users(id), book_id uuid REFERENCES books(id), rating int CHECK(rating BETWEEN 1 AND 5), body text, verified_purchase boolean DEFAULT false, moderation_status text DEFAULT 'PENDING', created_at timestamptz DEFAULT now(), UNIQUE(user_id,book_id));
CREATE TABLE library_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid REFERENCES users(id), format_id uuid REFERENCES book_formats(id), order_item_id uuid UNIQUE REFERENCES order_items(id), download_limit int NOT NULL, downloads_used int DEFAULT 0, granted_at timestamptz DEFAULT now(), UNIQUE(user_id,format_id));
CREATE TABLE download_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), library_item_id uuid REFERENCES library_items(id), ip_hash text, user_agent_hash text, downloaded_at timestamptz DEFAULT now());
CREATE TABLE recently_viewed (user_id uuid REFERENCES users(id), book_id uuid REFERENCES books(id), viewed_at timestamptz DEFAULT now(), PRIMARY KEY(user_id,book_id));
CREATE TABLE newsletter_subscribers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text UNIQUE NOT NULL, locale varchar(10), consented_at timestamptz NOT NULL DEFAULT now(), unsubscribed_at timestamptz);
CREATE TABLE contact_messages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text NOT NULL, subject text NOT NULL, body text NOT NULL, status text DEFAULT 'NEW', created_at timestamptz DEFAULT now());
CREATE TABLE site_settings (key text PRIMARY KEY, value jsonb NOT NULL, updated_at timestamptz DEFAULT now());
CREATE TABLE audit_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), actor_id uuid REFERENCES users(id), action text NOT NULL, entity_type text NOT NULL, entity_id text, metadata jsonb, created_at timestamptz DEFAULT now());
